package com.chaobo.scm.supplier.infrastructure.persistence.contract;import org.apache.ibatis.annotations.*;import java.time.*;
@Mapper public interface SupplierContractMapper{record Row(long id,String no,long supplier,Long quote,String agreement,String type,LocalDate from,LocalDate to,int status,String terms,String attachment,String reason,int version){}@Select("SELECT contract_id id,contract_no no,supplier_id supplier,quote_id quote,price_agreement_ref agreement,contract_type type,effective_from `from`,effective_to `to`,contract_status status,terms_json terms,attachment_url attachment,termination_reason reason,version FROM sup_supplier_contract WHERE contract_id=#{id} AND deleted=0")Row find(long id);@Insert("INSERT INTO sup_supplier_contract(contract_id,contract_no,supplier_id,quote_id,price_agreement_ref,contract_type,effective_from,effective_to,contract_status,terms_json,attachment_url,termination_reason,created_by,updated_by,version,deleted) VALUES(#{r.id},#{r.no},#{r.supplier},#{r.quote},#{r.agreement},#{r.type},#{r.from},#{r.to},#{r.status},CAST(#{r.terms} AS JSON),#{r.attachment},#{r.reason},#{op},#{op},#{r.version},0)")void insert(@Param("r")Row r,@Param("op")long op);@Update("UPDATE sup_supplier_contract SET effective_to=#{r.to},contract_status=#{r.status},terms_json=CAST(#{r.terms} AS JSON),attachment_url=#{r.attachment},termination_reason=#{r.reason},updated_by=#{op},version=#{r.version} WHERE contract_id=#{r.id} AND version=#{expected} AND deleted=0")int update(@Param("r")Row r,@Param("expected")int expected,@Param("op")long op);@Select("<script>SELECT COUNT(*) FROM sup_supplier_contract WHERE deleted=0 <if test='supplierId!=null'>AND supplier_id=#{supplierId}</if><if test='status!=null'>AND contract_status=#{status}</if><if test='keyword!=null and keyword!=\"\"'>AND contract_no LIKE CONCAT('%',#{keyword},'%')</if></script>")long count(@Param("supplierId")Long supplierId,@Param("status")Integer status,@Param("keyword")String keyword);@Select("<script>SELECT contract_id id,contract_no no,supplier_id supplier,quote_id quote,price_agreement_ref agreement,contract_type type,effective_from `from`,effective_to `to`,contract_status status,terms_json terms,attachment_url attachment,termination_reason reason,version FROM sup_supplier_contract WHERE deleted=0 <if test='supplierId!=null'>AND supplier_id=#{supplierId}</if><if test='status!=null'>AND contract_status=#{status}</if><if test='keyword!=null and keyword!=\"\"'>AND contract_no LIKE CONCAT('%',#{keyword},'%')</if> ORDER BY updated_at DESC LIMIT #{offset},#{size}</script>")java.util.List<Row> page(@Param("supplierId")Long supplierId,@Param("status")Integer status,@Param("keyword")String keyword,@Param("offset")int offset,@Param("size")int size);}
